.nx-group-control-container.cssGrpLOCK {
  opacity: 0.9;
  pointer-events: none;
  filter: grayscale(100%);
}
.nf-branding-head{
    height: 135px !important;
    margin-bottom: 0px !important;
}
.ManageApproval{
    background-color: #ffce00;
    height: 40px;
    color: black !important;
    padding-left: 10px;
    padding-bottom: 5px;
    font-weight: bold;
    border-radius: 10px;
    margin-bottom: -15px;
    }
